package be.schaubroeck.lpb.rkm.rekenmotor.service.web;

import be.schaubroeck.context.ConfigConstants;
import be.schaubroeck.context.ExecutionContext;
import be.schaubroeck.lpb.rkm.rekenmotor.RekenContext;
import be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenActionParamKey;
import be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenActionType;
import be.schaubroeck.lpb.rkm.rekenmotor.mapkeys.RekenAtoom;
import be.schaubroeck.lpb.rkm.rekenmotor.service.RekenActionFactory;
import be.schaubroeck.lpb.tools.Admin;
import be.schaubroeck.lpb.tools.ArtikelHoofd;
import be.schaubroeck.lpb.tools.ElektronischeVoorbereiding;
import be.schaubroeck.lpb.tools.RekenHoofd;
import be.schaubroeck.lpb.tools.Werkgever;
import be.schaubroeck.lpb.tools.enumtypes.Rekenmodus;
import be.schaubroeck.lpb.tools.exception.MessageException;
import com.google.common.collect.ArrayListMultimap;
import com.google.common.collect.Multimap;
import com.google.common.collect.Multimaps;
import com.google.common.collect.SetMultimap;
import org.joda.time.LocalDate;
import org.springframework.beans.factory.annotation.Autowired;

import java.util.ArrayList;
import java.util.Collection;
import java.util.Collections;
import java.util.List;
import java.util.Map;
import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.ExecutorService;
import java.util.concurrent.Future;
import java.util.concurrent.atomic.AtomicLong;

public class RekenProcesCentral {

    @Autowired
    private RekenActionFactory rekenActionFactory;

    @Autowired
    private final ExecutorService procesExecutor = null;

    private static final RekenProcesCentral instance = new RekenProcesCentral();

    private Map<Long, RekenProces> processen = new ConcurrentHashMap<>();
    private Multimap<Integer, RekenProces> adminToProcessen = Multimaps.synchronizedListMultimap(ArrayListMultimap.create());

    private AtomicLong procesIdGenerator = new AtomicLong(0);

    private RekenProcesCentral() {
    }

    public static RekenProcesCentral getInstance() {
        return instance;
    }

    public List<RekenProces> getProcessen() {
        return Collections.unmodifiableList(new ArrayList<>(processen.values()));
    }

    public List<RekenProces> getProcessen(Admin admin) {
        ExecutionContext ec = ExecutionContext.getContext();
        String tenant = ec.getUserAttribute(ConfigConstants.TENANT_EC_ATTR);
        List<RekenProces> processen = getProcessen();
        List<RekenProces> result = new ArrayList<>();
        for (RekenProces proces : processen) {
            if (proces.getAdminId() == admin.getId() && proces.getTenant().equals(tenant)) {
                result.add(proces);
            }
        }
        return result;
    }

    public Long startProces(Werkgever werkgever, Rekenmodus modus, String omschrijving, String actor) {
        Admin admin = werkgever.getAdmin();
        RekenContext actionParams = new RekenContext();
        actionParams.put(RekenActionParamKey.REKENMODUS_KEY, modus);
        actionParams.put(RekenActionParamKey.WERKGEVER_KEY, werkgever);

        RekenActionType type = RekenActionType.REKEN_UIT_REKENAGENDA;

        return startProces(admin, type, actionParams, omschrijving, actor);
    }

    public Long startVoorbereidingProces(
            Admin admin, Collection<ElektronischeVoorbereiding> voorbereidingen, String omschrijving, String actor, RekenActionType rekenActionType) {
        RekenContext actionParams = new RekenContext();
        actionParams.put(RekenActionParamKey.REKENMODUS_KEY, Rekenmodus.NORMAAL);
        actionParams.put(RekenActionParamKey.VOORBEREIDINGEN_KEY, voorbereidingen);

        return startProces(admin, rekenActionType, actionParams, omschrijving, actor);
    }

    public Long startArtikelAgendaProces(Admin admin, Collection<Integer> agendaIds, String omschrijving, String actor) {
        RekenContext actionParams = new RekenContext();
        actionParams.put(RekenActionParamKey.REKENMODUS_KEY, Rekenmodus.VORM_ARTIKELS);
        actionParams.put(RekenActionParamKey.ARTIKEL_AGENDA_IDS_KEY, agendaIds);

        RekenActionType type = RekenActionType.REKEN_UIT_ARTIKELAGENDA;
        return startProces(admin, type, actionParams, omschrijving, actor);
    }

    public Long startHerrekenProces(Admin admin, String omschrijving, String actor) {
        RekenContext actionParams = new RekenContext();
        RekenActionType type = RekenActionType.HERREKEN_ALLE_BEREKENDEN;
        return startProces(admin, type, actionParams, omschrijving, actor);
    }

    public Long startProces(Admin admin, RekenActionType type, RekenContext actionParams, String omschrijving, String actor) {
        checkActiveForAdmin(admin);
        Long procesId = procesIdGenerator.incrementAndGet();
        ExecutionContext ec = ExecutionContext.getContext();
        String tenant = ec.getUserAttribute(ConfigConstants.TENANT_EC_ATTR);
        RekenProces proces = new RekenProcesImp(admin, procesId.toString(), rekenActionFactory, omschrijving, actor, type, actionParams, tenant);
        processen.put(procesId, proces);
        adminToProcessen.put(admin.getId(), proces);
        Future<?> future = procesExecutor.submit(proces);
        proces.setFuture(future);
        return procesId;
    }

    public Long startHerrekenViaBoekDatumProces(
            Admin admin, Integer rnummer, LocalDate boekDatum, Integer boekjaar, SetMultimap<RekenAtoom, Integer> rekenAtomenMap,
            SetMultimap<RekenAtoom, Integer> atomenOldToOpdrachtNrMap, Map<RekenAtoom, RekenAtoom> rekenAtomenOldMap, List<ArtikelHoofd> artikelHoofden,
            List<RekenHoofd> rekenHoofden, String omschrijving, String actor) {
        checkActiveForAdmin(admin);
        Long procesId = procesIdGenerator.incrementAndGet();
        ExecutionContext ec = ExecutionContext.getContext();
        String tenant = ec.getUserAttribute(ConfigConstants.TENANT_EC_ATTR);
        RekenContext actionParams = new RekenContext();
        actionParams.put(RekenActionParamKey.RNUMMER_KEY, rnummer);
        actionParams.put(RekenActionParamKey.BOEK_DATUM_KEY, boekDatum);
        actionParams.put(RekenActionParamKey.ARTIKEL_HOOFDEN_KEY, artikelHoofden);
        actionParams.put(RekenActionParamKey.REKEN_HOOFDEN_KEY, rekenHoofden);
        actionParams.put(RekenActionParamKey.BOEKJAAR_KEY, boekjaar);
        actionParams.put(RekenActionParamKey.REKEN_ATOMEN_KEY, rekenAtomenMap);
        actionParams.put(RekenActionParamKey.REKEN_ATOMEN_OLD_KEY, rekenAtomenOldMap);
        actionParams.put(RekenActionParamKey.ATOMEN_OLD_TO_OPDRACHT_NR_KEY, atomenOldToOpdrachtNrMap);
        RekenProces proces =
                new RekenProcesImp(admin, procesId.toString(), rekenActionFactory, omschrijving, actor, RekenActionType.HERREKEN_VIA_BOEKDATUM, actionParams, tenant);
        processen.put(procesId, proces);
        adminToProcessen.put(admin.getId(), proces);
        Future<?> future = procesExecutor.submit(proces);
        proces.setFuture(future);
        return procesId;
    }

    private void checkActiveForAdmin(Admin admin) {
        Collection<RekenProces> processenVoorAdmin = adminToProcessen.get(admin.getId());
        for (RekenProces proces : processenVoorAdmin) {
            if (!proces.isFinished()) {
                throw new MessageException("Er loopt nog een Rekenproces voor deze admin");
            }
        }
    }

    public boolean cancelProces(Long procesId) {
        RekenProces proces = processen.get(procesId);
        boolean success = false;
        if (proces != null) {
            proces.halt();
        }
        return success;
    }

    public RekenProces getProces(Long procesId) {
        return processen.get(procesId);
    }
}
